<script setup lang="ts">
import { useBacktestApi } from '@/composables/useBacktestApi';

const props = withDefaults(
  defineProps<{
    modelValue: string;
    showDetails?: boolean;
  }>(),
  {
    showDetails: false,
  },
);
const emit = defineEmits<{ 'update:modelValue': [value: string] }>();

const bt = useBacktestApi();

const strategyCode = ref<string>('');
const locStrategy = computed({
  get() {
    return props.modelValue;
  },
  set(strategy: string) {
    bt.getStrategy(strategy).then((data) => {
      strategyCode.value = data?.code ?? '';
    });
    emit('update:modelValue', strategy);
  },
});

onMounted(() => {
  if (bt.strategyList.value.length === 0) {
    bt.getStrategyList();
  }
});
</script>

<template>
  <div>
    <div class="w-full flex">
      <Select
        id="strategy-select"
        v-model="locStrategy"
        filter
        fluid
        :options="bt.strategyList"
      >
      </Select>
      <div class="ms-1">
        <Button severity="secondary" variant="outlined" @click="bt.getStrategyList">
          <template #icon>
            <i-lucide-refresh-cw />
          </template>
        </Button>
      </div>
    </div>

    <textarea
      v-if="showDetails && strategyCode"
      v-model="strategyCode"
      class="w-full h-full"
    ></textarea>
  </div>
</template>
